// GET /api/admin/membership-plans
exports.getAll = async (req, res, next) => {
  try {
    const { page = 1, limit = 20, search, status } = req.query;
    const offset = (page - 1) * limit;

    let query = `SELECT * FROM membership_plans WHERE 1=1`;
    const params = [];
    let paramIndex = 1;

    if (search) {
      query += ` AND (slug ILIKE $${paramIndex} OR name::text ILIKE $${paramIndex})`;
      params.push(`%${search}%`);
      paramIndex++;
    }

    if (status && status !== 'undefined') {
      query += ` AND status = $${paramIndex}`;
      params.push(status);
      paramIndex++;
    }

    query += ` ORDER BY created_at DESC LIMIT $${paramIndex} OFFSET $${paramIndex + 1}`;
    params.push(parseInt(limit), offset);

    const { rows } = await pool.query(query, params);

    // Get total count with same filters
    let countQuery = 'SELECT COUNT(*) as total FROM membership_plans WHERE 1=1';
    const countParams = [];
    let countParamIndex = 1;

    if (search) {
      countQuery += ` AND (slug ILIKE $${countParamIndex} OR name::text ILIKE $${countParamIndex})`;
      countParams.push(`%${search}%`);
      countParamIndex++;
    }

    if (status && status !== 'undefined') {
      countQuery += ` AND status = $${countParamIndex}`;
      countParams.push(status);
      countParamIndex++;
    }

    const { rows: countRows } = await pool.query(countQuery, countParams);

    return res.json({
      success: true,
      data: rows,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total: parseInt(countRows[0].total),
        totalPages: Math.ceil(countRows[0].total / limit),
      },
    });
  } catch (error) {
    return next(error);
  }
};

// GET /api/admin/membership-plans/:id
exports.getById = async (req, res, next) => {
  try {
    const { id } = req.params;
    const { rows } = await pool.query('SELECT * FROM membership_plans WHERE id = $1', [id]);

    if (rows.length === 0) {
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy membershipplan',
      });
    }

    return res.json({
      success: true,
      data: rows[0],
    });
  } catch (error) {
    return next(error);
  }
};

// POST /api/admin/membership-plans
exports.create = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const jsonTypeMap = await getMembershipColumnTypes(client);
    const allowedColumns = await getMembershipAllowedColumns(client);
    const normalizedInput = normalizeMembershipInput(req.body, jsonTypeMap);
    const data = filterMembershipInputBySchema(normalizedInput, allowedColumns);

    if (Object.keys(data).length === 0) {
      await client.query('ROLLBACK');
      return res.status(400).json({
        success: false,
        message: 'Không có trường dữ liệu hợp lệ để tạo gói hội viên',
      });
    }

    const fields = Object.keys(data).join(', ');
    const values = Object.keys(data).map((_, i) => `$${i + 1}`).join(', ');
    const params = Object.values(data);

    const { rows } = await client.query(
      `INSERT INTO membership_plans (${fields}) VALUES (${values}) RETURNING *`,
      params
    );

    await client.query('COMMIT');

    return res.status(201).json({
      success: true,
      message: 'Đã tạo membershipplan thành công',
      data: rows[0],
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};

